"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[9983],{3805(t,e,d){d.r(e),d.d(e,{comp:()=>o,data:()=>i});var n=d(641);const r={},o=(0,d(6262).A)(r,[["render",function(t,e){return(0,n.uX)(),(0,n.CE)("div",null,[...e[0]||(e[0]=[(0,n.Fv)('<h1 id="add-edit-auction" tabindex="-1"><a class="header-anchor" href="#add-edit-auction"><span>Add / Edit Auction</span></a></h1><p><strong>Auctions → Add Auction</strong> — <code>?page=wkafw-add-auction</code><strong>Auctions → All Auctions → row → Edit</strong> — <code>?page=wkafw-add-auction&amp;auction_id=N</code></p><p>A single-screen form. Field-by-field reference below — top to bottom in the order you&#39;d fill it.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-add-auction.png" alt="Add Auction — single-screen creation form linking a WooCommerce product to auction settings"></p><h2 id="section-1-—-product-link" tabindex="-1"><a class="header-anchor" href="#section-1-—-product-link"><span>Section 1 — Product link</span></a></h2><p>The auction must reference a WooCommerce product. You have two options:</p><table><thead><tr><th>Option</th><th>When to use</th></tr></thead><tbody><tr><td><strong>Link existing product</strong></td><td>The product already exists (e.g. &quot;Vintage Rolex Submariner&quot;)</td></tr><tr><td><strong>Create new product</strong></td><td>Spins up a hidden product on save and links it</td></tr></tbody></table><p>The product type is automatically set to <code>auction</code> (the custom WooCommerce product type registered by the plugin).</p><h3 id="item-condition" tabindex="-1"><a class="header-anchor" href="#item-condition"><span>Item condition</span></a></h3><p>Dropdown — <strong>New / Like New / Used / Refurbished / For Parts</strong>. Persisted to <code>wkafw_auctions.item_condition</code> and shown on the storefront.</p><h2 id="section-2-—-auction-type" tabindex="-1"><a class="header-anchor" href="#section-2-—-auction-type"><span>Section 2 — Auction type</span></a></h2><p>Dropdown listing only the <a href="/admin-settings.html#auction-types" target="_blank" rel="noopener noreferrer">enabled auction types</a>.</p><table><thead><tr><th>Type</th><th>Mode</th><th>Wins by</th></tr></thead><tbody><tr><td><a href="/auction-types.html#standard" target="_blank" rel="noopener noreferrer">Standard</a></td><td>Forward</td><td>Highest bid</td></tr><tr><td><a href="/auction-types.html#reverse" target="_blank" rel="noopener noreferrer">Reverse</a></td><td>Reverse</td><td>Lowest bid</td></tr><tr><td><a href="/auction-types.html#sealed" target="_blank" rel="noopener noreferrer">Sealed</a></td><td>Forward, hidden</td><td>Highest bid (revealed at close)</td></tr><tr><td><a href="/auction-types.html#proxy" target="_blank" rel="noopener noreferrer">Proxy</a></td><td>Forward, auto-bid</td><td>Highest bid (system bids on user&#39;s behalf)</td></tr><tr><td><a href="/auction-types.html#silent" target="_blank" rel="noopener noreferrer">Silent</a></td><td>Forward</td><td>Highest bid (paddles + ballot)</td></tr><tr><td><a href="/auction-types.html#charity" target="_blank" rel="noopener noreferrer">Charity</a></td><td>Forward + receipt</td><td>Highest bid</td></tr><tr><td><a href="/auction-types.html#penny" target="_blank" rel="noopener noreferrer">Penny</a></td><td>Pay-per-bid</td><td>Last bid before timer hits zero</td></tr><tr><td><a href="/auction-types.html#dutch" target="_blank" rel="noopener noreferrer">Dutch</a></td><td>Descending</td><td>First to accept current price</td></tr><tr><td><a href="/auction-types.html#seated" target="_blank" rel="noopener noreferrer">Seated</a></td><td>Live event</td><td>Highest paddle</td></tr><tr><td><a href="/auction-types.html#unique-bid" target="_blank" rel="noopener noreferrer">Unique-Bid</a></td><td>Sealed</td><td>Lowest unique bid</td></tr></tbody></table><p>Selecting a type may show / hide fields below (e.g. <strong>Pack Size</strong> appears for Penny; <strong>Seat Count</strong> for Seated).</p><h2 id="section-3-—-pricing" tabindex="-1"><a class="header-anchor" href="#section-3-—-pricing"><span>Section 3 — Pricing</span></a></h2><table><thead><tr><th>Field</th><th>Required</th><th>Note</th></tr></thead><tbody><tr><td><strong>Start price</strong></td><td>yes</td><td>What bidding opens at</td></tr><tr><td><strong>Reserve price</strong></td><td>no (set to start price to disable)</td><td>Hidden from bidders; auction fails if not met</td></tr><tr><td><strong>Buy It Now price</strong></td><td>no (<code>0</code> to disable)</td><td>Optional fixed-price instant purchase</td></tr><tr><td><strong>Bid increment</strong></td><td>yes</td><td>See below</td></tr></tbody></table><h3 id="bid-increment" tabindex="-1"><a class="header-anchor" href="#bid-increment"><span>Bid increment</span></a></h3><p>Three modes:</p><table><thead><tr><th>Mode</th><th>Field</th><th>Example</th></tr></thead><tbody><tr><td><strong>Fixed</strong></td><td>single number</td><td>Always +$10</td></tr><tr><td><strong>Variable</strong></td><td>tier table</td><td>+$5 under $100, +$25 under $500, +$100 above</td></tr><tr><td><strong>Percentage</strong></td><td>single %</td><td>Always +5% of current bid</td></tr></tbody></table><p><a href="/bid-increments.html" target="_blank" rel="noopener noreferrer">Bid increments deep-dive →</a></p><h3 id="buy-now-auto-disable-rules" tabindex="-1"><a class="header-anchor" href="#buy-now-auto-disable-rules"><span>Buy Now auto-disable rules</span></a></h3><p>If you set a Buy Now price, you can choose when it disappears:</p><ul><li>Always visible</li><li>Hide after first bid</li><li>Hide after reserve met</li><li>Hide after N bids</li></ul><p><a href="/reserve-buy-now.html" target="_blank" rel="noopener noreferrer">Reserve &amp; Buy Now →</a></p><h2 id="section-4-—-schedule" tabindex="-1"><a class="header-anchor" href="#section-4-—-schedule"><span>Section 4 — Schedule</span></a></h2><table><thead><tr><th>Field</th><th>Note</th></tr></thead><tbody><tr><td><strong>Start date / time</strong></td><td>Auction goes live at this moment (status → <code>active</code>)</td></tr><tr><td><strong>End date / time</strong></td><td>Bidding closes; lifecycle worker picks a winner</td></tr><tr><td><strong>Anti-snipe window</strong></td><td>Last-N-seconds trigger window (default <code>60</code>)</td></tr><tr><td><strong>Anti-snipe extension</strong></td><td>Add-N-seconds when triggered (default <code>120</code>)</td></tr><tr><td><strong>Max extension cap</strong></td><td>Total cumulative extension cap; <code>0</code> = unlimited</td></tr></tbody></table><p><a href="/anti-sniping.html" target="_blank" rel="noopener noreferrer">Anti-sniping →</a></p><div class="hint-container tip"><p class="hint-container-title">Schedule into the future</p><p>Set a start date in the future to schedule the auction. It saves as <code>scheduled</code> and flips to <code>active</code> automatically when the cron worker fires.</p></div><h2 id="section-5-—-bidding-rules-advanced" tabindex="-1"><a class="header-anchor" href="#section-5-—-bidding-rules-advanced"><span>Section 5 — Bidding rules (advanced)</span></a></h2><table><thead><tr><th>Field</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Allow retraction</strong></td><td>off</td><td>Bidder can pull a bid within the retraction window</td></tr><tr><td><strong>Retraction window</strong></td><td><code>300</code> s</td><td>Time to retract after placing</td></tr><tr><td><strong>Bid cooldown</strong></td><td><code>5</code> s</td><td>Min wait between bids by same user</td></tr><tr><td><strong>Max bids per user</strong></td><td>unlimited</td><td>Cap on one user&#39;s bid count</td></tr><tr><td><strong>Max total bids</strong></td><td>unlimited</td><td>Cap on total bid count</td></tr><tr><td><strong>Bid confirmation</strong></td><td>off</td><td>&quot;Are you sure?&quot; modal before placing</td></tr><tr><td><strong>Anonymous bidding</strong></td><td>off</td><td>Allow bidders to mark themselves anonymous</td></tr></tbody></table><p><a href="/bidding-engine.html" target="_blank" rel="noopener noreferrer">Bidding engine →</a></p><h2 id="section-6-—-lifecycle-advanced" tabindex="-1"><a class="header-anchor" href="#section-6-—-lifecycle-advanced"><span>Section 6 — Lifecycle (advanced)</span></a></h2><table><thead><tr><th>Field</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Auto-relist on failure</strong></td><td>off</td><td>Re-list automatically if reserve not met</td></tr><tr><td><strong>Auto-relist on non-payment</strong></td><td>off</td><td>Re-list if winner doesn&#39;t pay in N hours</td></tr><tr><td><strong>Max relist attempts</strong></td><td><code>3</code></td><td>Stop after this many cycles</td></tr><tr><td><strong>Relist interval</strong></td><td><code>72</code> hrs</td><td>Wait between attempts</td></tr></tbody></table><p><a href="/auto-relist.html" target="_blank" rel="noopener noreferrer">Auto-relist →</a></p><h2 id="section-7-—-multi-vendor-if-applicable" tabindex="-1"><a class="header-anchor" href="#section-7-—-multi-vendor-if-applicable"><span>Section 7 — Multi-vendor (if applicable)</span></a></h2><p>If a multi-vendor plugin is active, the form shows a <strong>Vendor</strong> dropdown. The auction is assigned to the chosen vendor and, when it sells, the commission split is recorded against that vendor automatically.</p><p><a href="/multi-vendor.html" target="_blank" rel="noopener noreferrer">Multi-vendor →</a></p><h2 id="section-8-—-notifications" tabindex="-1"><a class="header-anchor" href="#section-8-—-notifications"><span>Section 8 — Notifications</span></a></h2><p>Per-auction overrides for the global email settings. Use these to silence specific emails (e.g. for a private VIP auction) or to add specific recipients.</p><p><a href="/notifications.html" target="_blank" rel="noopener noreferrer">Email notifications →</a></p><h2 id="save-buttons" tabindex="-1"><a class="header-anchor" href="#save-buttons"><span>Save buttons</span></a></h2><table><thead><tr><th>Button</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Publish</strong></td><td>Saves and goes live (or schedules if start date is future)</td></tr><tr><td><strong>Save Draft</strong></td><td>Saves without publishing — draft auctions are not visible publicly</td></tr><tr><td><strong>Schedule</strong></td><td>Same as Publish, but explicit about future start date</td></tr><tr><td><strong>Update</strong> (edit mode)</td><td>Saves changes; status is preserved</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Editing a live auction</p><p>Some fields are locked once bidding starts: <strong>start price</strong>, <strong>bid increment</strong>, <strong>auction type</strong>. To change them, you must end / cancel and re-create the auction. The plugin shows a notice when you try.</p></div><h2 id="validation-rules" tabindex="-1"><a class="header-anchor" href="#validation-rules"><span>Validation rules</span></a></h2><p>The form validates server-side before save:</p><table><thead><tr><th>Rule</th><th>Error</th></tr></thead><tbody><tr><td>End date &gt; start date</td><td>&quot;End must be after start&quot;</td></tr><tr><td>Reserve ≥ start price</td><td>&quot;Reserve must be ≥ start&quot;</td></tr><tr><td>Buy Now &gt; start price + increment</td><td>&quot;Buy Now too low&quot;</td></tr><tr><td>Increment &gt; 0</td><td>&quot;Increment must be positive&quot;</td></tr><tr><td>Variable tier table sorted</td><td>&quot;Tier ranges must be ascending&quot;</td></tr><tr><td>Anti-snipe window ≥ 0</td><td>&quot;Window cannot be negative&quot;</td></tr><tr><td>Max extension cap ≥ 0</td><td>&quot;Cap cannot be negative&quot;</td></tr></tbody></table><p>Errors render at the top of the form; the failing field is scrolled into view.</p><h2 id="after-saving" tabindex="-1"><a class="header-anchor" href="#after-saving"><span>After saving</span></a></h2><ul><li>A row is created in <code>wkafw_auctions</code></li><li>An entry is appended to <code>wkafw_auction_logs</code> (<code>action: created</code>)</li><li>If the start date is in the past, status flips to <code>active</code> immediately and the auction is visible on the storefront</li><li>The cron worker schedules <code>wkafw_auction_starting</code> and <code>wkafw_auction_ending_soon</code> notifications</li></ul><h2 id="common-gotchas" tabindex="-1"><a class="header-anchor" href="#common-gotchas"><span>Common gotchas</span></a></h2><table><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Auction not visible on storefront</td><td>Status is <code>draft</code> or <code>scheduled</code>; check <strong>All Auctions</strong> filter</td></tr><tr><td>Bid increment field grayed out</td><td>Auction has bids — locked</td></tr><tr><td>Reserve &quot;not met&quot; message even when bid &gt; reserve</td><td>Reserve was changed after bid; re-check field</td></tr><tr><td>End date won&#39;t save</td><td>Site timezone mismatch; check <strong>Settings → General → Timezone</strong></td></tr></tbody></table>',51)])])}]]),i=JSON.parse('{"path":"/admin-add-auction.html","title":"Add / Edit Auction","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Section 1 — Product link","slug":"section-1-—-product-link","link":"#section-1-—-product-link","children":[{"level":3,"title":"Item condition","slug":"item-condition","link":"#item-condition","children":[]}]},{"level":2,"title":"Section 2 — Auction type","slug":"section-2-—-auction-type","link":"#section-2-—-auction-type","children":[]},{"level":2,"title":"Section 3 — Pricing","slug":"section-3-—-pricing","link":"#section-3-—-pricing","children":[{"level":3,"title":"Bid increment","slug":"bid-increment","link":"#bid-increment","children":[]},{"level":3,"title":"Buy Now auto-disable rules","slug":"buy-now-auto-disable-rules","link":"#buy-now-auto-disable-rules","children":[]}]},{"level":2,"title":"Section 4 — Schedule","slug":"section-4-—-schedule","link":"#section-4-—-schedule","children":[]},{"level":2,"title":"Section 5 — Bidding rules (advanced)","slug":"section-5-—-bidding-rules-advanced","link":"#section-5-—-bidding-rules-advanced","children":[]},{"level":2,"title":"Section 6 — Lifecycle (advanced)","slug":"section-6-—-lifecycle-advanced","link":"#section-6-—-lifecycle-advanced","children":[]},{"level":2,"title":"Section 7 — Multi-vendor (if applicable)","slug":"section-7-—-multi-vendor-if-applicable","link":"#section-7-—-multi-vendor-if-applicable","children":[]},{"level":2,"title":"Section 8 — Notifications","slug":"section-8-—-notifications","link":"#section-8-—-notifications","children":[]},{"level":2,"title":"Save buttons","slug":"save-buttons","link":"#save-buttons","children":[]},{"level":2,"title":"Validation rules","slug":"validation-rules","link":"#validation-rules","children":[]},{"level":2,"title":"After saving","slug":"after-saving","link":"#after-saving","children":[]},{"level":2,"title":"Common gotchas","slug":"common-gotchas","link":"#common-gotchas","children":[]}],"git":{},"filePathRelative":"admin-add-auction.md"}')}}]);